```class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        unordered_map<int, int> countMap;
        for (int num : arr) {
            countMap[num]++;
        }
        for (auto pair : countMap) {
            if (pair.second != arr.size()) {
                return false;
            }
        }
        return true;
    }
};```

